class BaseTask:
    def __init__(self, title, points):
        self.title = title
        self.points = max(0, points)
        self.done = False

    def mark_done(self):
        self.done = True

    def summary_line(self):
        status = "done" if self.done else "open"
        return f"{self.title} [{status}] - {self.points} pts"

from models.base_task import BaseTask


class BugTask(BaseTask):
    def __init__(self, title, points, severity):
        super().__init__(title, points)
        self.severity = severity

    def summary_line(self):
        status = "done" if self.done else "open"
        return f"BUG {self.severity}: {self.title} [{status}] - {self.points} pts"

from models.base_task import BaseTask


class FeatureTask(BaseTask):
    def __init__(self, title, points, area):
        super().__init__(title, points)
        self.area = area

    def summary_line(self):
        status = "done" if self.done else "open"
        return f"FEATURE {self.area}: {self.title} [{status}] - {self.points} pts"

class BugTask:
    def __init__(self, title, priority, value_3):
        pass

    def summary(self):
        return f"BUG: {self.title} | priority={self.priority} | severity={self.value_3} | done=False"

def build_summary(tasks):
    return [task.summary_line() for task in tasks]


def total_points(tasks):
    return sum(task.points for task in tasks)


def done_count(tasks):
    return sum(1 for task in tasks if task.status == "done")


def priority_breakdown(tasks):
    return [task.priority_label() for task in tasks]

from models.bug_task import BugTask
from models.feature_task import FeatureTask


def load_tasks(task_rows):
    tasks = []
    for row in task_rows:
        if row["type"] == "bug":
            tasks.append(BugTask(row["title"], row["points"]))
        elif row["type"] == "feature":
            tasks.append(FeatureTask(row["title"], row["points"]))
    return tasks

